export interface ApiKeyCreds {
  key: string
  secret: string
  passphrase: string
}

export interface ApiKeyRaw {
  apiKey: string
  secret: string
  passphrase: string
}

export interface ApiKeysResponse {
  apiKeys: ApiKeyCreds[]
}
export interface AuthIdentity {
  /**
   * CAIP-10 account identifier, e.g. "eip155:1:0x1234..."
   */
  account: string
  /**
   * Chain namespace per CAIP-2, e.g. "eip155" | "solana"
   */
  namespace: string
  /**
   * Chain or network identifier, e.g. "1", "56", "mainnet-beta"
   */
  chainId: string
  /**
   * Raw wallet address or public key, e.g. "0x1234..." | "9xQeWvG..."
   */
  address: string
}

export interface L3AuthRequest {
  identity: AuthIdentity
  message: string
  signature: string
  nonce: string
  issuedAt: string
}

export interface L3Session {
  identity: AuthIdentity
  issuedAt: string
  expiresAt: string
}

export type LoginResponse = L3Session & {
  l3Session: string
}
